$Base64RequestPayload = "";


$DecryptedSek = "y5XmaaigS7l1KJsoo/seilAQP0wGtHr9AsbyQ/PSwoI=";

function encryptBySymmetricKey($dataB64, $sekB64){
		
    $data = base64_decode($dataB64);                                                // the data to encrypt
    $sek = base64_decode($sekB64);                                                  // the SEK
    $encDataB64 = openssl_encrypt($data, "aes-256-ecb", $sek, 0);                   // the Base64 encoded ciphertext
    return $encDataB64;
}

$reqpayload = encryptBySymmetricKey($Base64RequestPayload, $DecryptedSek);
echo "Encrypted Request Payload (Base64): " . $reqpayload;
